//
//     final package = packageFromJson(jsonString);

import 'dart:convert';

Package packageFromJson(String str) => Package.fromJson(json.decode(str));

String packageToJson(Package data) => json.encode(data.toJson());

class Package {
    String name;
    String author;
    String version;
    String description;
    String repository;
    String license;
    String main;
    List<String> keywords;
    Engines engines;
    Scripts scripts;
    DevDependencies devDependencies;
    List<String> files;

    Package({
        required this.name,
        required this.author,
        required this.version,
        required this.description,
        required this.repository,
        required this.license,
        required this.main,
        required this.keywords,
        required this.engines,
        required this.scripts,
        required this.devDependencies,
        required this.files,
    });

    factory Package.fromJson(Map<String, dynamic> json) => Package(
        name: json["name"],
        author: json["author"],
        version: json["version"],
        description: json["description"],
        repository: json["repository"],
        license: json["license"],
        main: json["main"],
        keywords: List<String>.from(json["keywords"].map((x) => x)),
        engines: Engines.fromJson(json["engines"]),
        scripts: Scripts.fromJson(json["scripts"]),
        devDependencies: DevDependencies.fromJson(json["devDependencies"]),
        files: List<String>.from(json["files"].map((x) => x)),
    );

    Map<String, dynamic> toJson() => {
        "name": name,
        "author": author,
        "version": version,
        "description": description,
        "repository": repository,
        "license": license,
        "main": main,
        "keywords": List<dynamic>.from(keywords.map((x) => x)),
        "engines": engines.toJson(),
        "scripts": scripts.toJson(),
        "devDependencies": devDependencies.toJson(),
        "files": List<dynamic>.from(files.map((x) => x)),
    };
}

class DevDependencies {
    String testRunnerWeb;
    String coveralls;
    String esmRunner;
    String jsdocToMarkdown;
    String rollup;
    String testObjectModel;
    String testRunner;

    DevDependencies({
        required this.testRunnerWeb,
        required this.coveralls,
        required this.esmRunner,
        required this.jsdocToMarkdown,
        required this.rollup,
        required this.testObjectModel,
        required this.testRunner,
    });

    factory DevDependencies.fromJson(Map<String, dynamic> json) => DevDependencies(
        testRunnerWeb: json["@test-runner/web"],
        coveralls: json["coveralls"],
        esmRunner: json["esm-runner"],
        jsdocToMarkdown: json["jsdoc-to-markdown"],
        rollup: json["rollup"],
        testObjectModel: json["test-object-model"],
        testRunner: json["test-runner"],
    );

    Map<String, dynamic> toJson() => {
        "@test-runner/web": testRunnerWeb,
        "coveralls": coveralls,
        "esm-runner": esmRunner,
        "jsdoc-to-markdown": jsdocToMarkdown,
        "rollup": rollup,
        "test-object-model": testObjectModel,
        "test-runner": testRunner,
    };
}

class Engines {
    String node;

    Engines({
        required this.node,
    });

    factory Engines.fromJson(Map<String, dynamic> json) => Engines(
        node: json["node"],
    );

    Map<String, dynamic> toJson() => {
        "node": node,
    };
}

class Scripts {
    String test;
    String testJs;
    String testEsm;
    String testWeb;
    String dist;
    String docs;
    String cover;

    Scripts({
        required this.test,
        required this.testJs,
        required this.testEsm,
        required this.testWeb,
        required this.dist,
        required this.docs,
        required this.cover,
    });

    factory Scripts.fromJson(Map<String, dynamic> json) => Scripts(
        test: json["test"],
        testJs: json["test:js"],
        testEsm: json["test:esm"],
        testWeb: json["test:web"],
        dist: json["dist"],
        docs: json["docs"],
        cover: json["cover"],
    );

    Map<String, dynamic> toJson() => {
        "test": test,
        "test:js": testJs,
        "test:esm": testEsm,
        "test:web": testWeb,
        "dist": dist,
        "docs": docs,
        "cover": cover,
    };
}
